107	function jsonResponse(status: number, body: unknown): Response {
108	  return new Response(JSON.stringify(body), {
109	    status,
110	    headers: { ...corsHeaders, "Content-Type": "application/json" },
111	  });
112	}
113	
114	function bearerToken(req: Request): string | null {
115	  const raw = req.headers.get("Authorization") ??
116	    req.headers.get("authorization");
117	  if (!raw) return null;
118	  const m = raw.match(/^Bearer\s+(.+)$/i);
119	  return m ? m[1].trim() : null;
120	}
121	
122	// Evaluate a single pre-condition against the creator's denormalized
123	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
124	// Missing data (null actual for a numeric threshold) fails closed per §3d.
125	function evaluatePreCondition(
126	  condition: ConditionRow,
127	  metrics: CreatorProfileRow,
128	): FailedCondition | null {
129	  const { metric, platform, operator } = condition;
130	  if (operator === "gte") {
131	    const required = Number(condition.numeric_threshold);
132	    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
133	    const actual = readNumericMetric(metrics, platform, metric);
134	    if (actual === null || actual < required) {
135	      return { metric, platform, required, actual };
136	    }
137	    return null;
138	  }
139	  if (operator === "bool") {
140	    const required = condition.bool_threshold === true;
141	    const actual = readBoolMetric(metrics, platform, metric);
142	    if (actual !== required) {
143	      return { metric, platform, required, actual };
144	    }
145	    return null;
146	  }
147	  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
148	  // are reserved for post-conditions today (e.g. post_must_mention uses
149	  // 'contains'), so this branch should be unreachable; if a future migration
150	  // misplaces an operator, we'd rather block an apply than silently allow it.
151	  console.warn("pre-condition with unknown operator treated as failed", {
152	    condition_id: condition.id,
153	    operator,
154	    metric,
155	    platform,
156	  });
157	  const parsed = Number(condition.numeric_threshold);
158	  return {
159	    metric,
160	    platform,
161	    required: Number.isFinite(parsed) ? parsed : 0,
162	    actual: null,
163	  };
164	}
165	
166	function readNumericMetric(
167	  metrics: CreatorProfileRow,
168	  platform: Platform | null,
169	  metric: string,
170	): number | null {
171	  if (platform === "tiktok") {
172	    switch (metric) {
173	      case "min_followers":
174	        return metrics.tiktok_follower_count;
175	      case "min_avg_views_last_n":
176	        return metrics.tiktok_avg_views_last_10;
177	      case "min_total_likes":
178	        return metrics.tiktok_total_likes;
179	      case "min_videos_posted":
180	        return metrics.tiktok_video_count;
181	      default:
182	        return null;
183	    }
184	  }
185	  if (platform === "instagram") {
186	    switch (metric) {
187	      case "min_followers":
188	        return metrics.instagram_follower_count;
189	      case "min_avg_views_last_n":
190	        return metrics.instagram_avg_views_last_10;
191	      case "min_videos_posted":
192	        return metrics.instagram_media_count;
193	      default:
194	        return null;
195	    }
196	  }
197	  return null;
198	}
199	
200	function readBoolMetric(
201	  metrics: CreatorProfileRow,
202	  platform: Platform | null,
203	  metric: string,
204	): boolean | null {
205	  if (platform === "tiktok" && metric === "verified_only") {
206	    return metrics.tiktok_is_verified;
207	  }
208	  return null;
209	}
210	
211	Deno.serve(async (req) => {
212	  if (req.method === "OPTIONS") {
213	    return new Response(null, { status: 204, headers: corsHeaders });
214	  }
215	  if (req.method !== "POST") {
216	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
217	  }
218	
219	  const token = bearerToken(req);
220	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
221	
222	  let claims;
223	  try {
224	    claims = await verifyJwt(token);
225	  } catch {
226	    return jsonResponse(401, { error: "UNAUTHORIZED" });
227	  }
228	  if (claims.role !== "creator") {
229	    return jsonResponse(403, { error: "FORBIDDEN" });
230	  }
231	
232	  let body: DetailRequest;
233	  try {
234	    body = await req.json();
235	  } catch {
236	    return jsonResponse(400, { error: "INVALID_JSON" });
237	  }
238	
239	  const listingId =
240	    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
241	      ? body.listing_id
242	      : null;
243	  if (!listingId) {
244	    return jsonResponse(400, { error: "INVALID_REQUEST" });
245	  }
246	
247	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
248	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
249	  if (!supabaseUrl || !serviceRoleKey) {
250	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
251	  }
252	
253	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
254	    auth: { persistSession: false, autoRefreshToken: false },
255	  });
256	
257	  const { data: listing, error: listingError } = await supabase
258	    .from("listings")
259	    .select("*")
260	    .eq("id", listingId)
261	    .maybeSingle();
262	
263	  if (listingError) {
264	    console.error("listings lookup failed", listingError);
265	    return jsonResponse(500, { error: "DB_ERROR" });
266	  }
267	  // Drafts are never visible to non-owners; archived is terminal and no
268	  // apply path can succeed against it. Both collapse to 404 so id
269	  // existence doesn't leak and the UI never lands on a dead-end detail
270	  // view. `paused`/`closed` stay accessible so a creator with an existing
271	  // application can still open the detail; the Apply CTA in US-040 gates
272	  // off `listing.status`.
273	  if (!listing || listing.status === "draft" || listing.status === "archived") {
274	    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
275	  }
276	
277	  const versionId = listing.current_version_id as string | null;
278	  if (!versionId) {
279	    // Data-integrity guard — publish (US-010 POST /listings) is what sets
280	    // `current_version_id` on the first version; the bump trigger updates
281	    // it on subsequent edits. A non-draft/non-archived listing without a
282	    // current_version_id is a persistence bug, not a normal state — fail
283	    // with DB_ERROR rather than return an inconsistent response.
284	    console.error("listing missing current_version_id", listing.id);
285	    return jsonResponse(500, { error: "DB_ERROR" });
286	  }
287	
288	  const [conditionsRes, videosRes, profileRes, appsRes] = await Promise.all([
289	    supabase
290	      .from("listing_conditions")
291	      .select("*")
292	      .eq("listing_version_id", versionId)
293	      .order("kind", { ascending: true })
294	      .order("metric", { ascending: true }),
295	    supabase
296	      .from("sample_videos")
297	      .select("*")
298	      .eq("listing_version_id", versionId)
299	      .order("sort_order", { ascending: true }),
300	    supabase
301	      .from("creator_profiles")
302	      .select(
303	        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
304	          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
305	          "instagram_avg_views_last_10,instagram_media_count",
306	      )
307	      .eq("user_id", claims.sub)
308	      .maybeSingle(),
309	    supabase
310	      .from("applications")
311	      .select("id")
312	      .eq("listing_id", listingId)
313	      .eq("creator_id", claims.sub)
314	      .in("status", ["pending", "approved"])
315	      .limit(1),
316	  ]);
317	
318	  if (conditionsRes.error) {
319	    console.error("listing_conditions lookup failed", conditionsRes.error);
320	    return jsonResponse(500, { error: "DB_ERROR" });
321	  }
322	  if (videosRes.error) {
323	    console.error("sample_videos lookup failed", videosRes.error);
324	    return jsonResponse(500, { error: "DB_ERROR" });
325	  }
326	  if (profileRes.error) {
327	    console.error("creator_profiles lookup failed", profileRes.error);
328	    return jsonResponse(500, { error: "DB_ERROR" });
329	  }
330	  if (appsRes.error) {
331	    console.error("applications lookup failed", appsRes.error);
332	    return jsonResponse(500, { error: "DB_ERROR" });
333	  }
334	
335	  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
336	
337	  // Creator profile is created by the signup flow (US-014) so every
338	  // creator JWT should have one, but treat a missing row as fully-null
339	  // metrics — fail-closed on every numeric threshold.
340	  const metrics: CreatorProfileRow = profileRes.data ?? {
341	    tiktok_follower_count: null,
342	    tiktok_avg_views_last_10: null,
343	    tiktok_total_likes: null,
344	    tiktok_video_count: null,
345	    tiktok_is_verified: null,
346	    instagram_follower_count: null,
347	    instagram_avg_views_last_10: null,
348	    instagram_media_count: null,
349	  };
350	
351	  const failed: FailedCondition[] = [];
352	  for (const c of conditions) {
353	    if (c.kind !== "pre") continue;
354	    const miss = evaluatePreCondition(c, metrics);
355	    if (miss) failed.push(miss);
356	  }
357	  const eligible = failed.length === 0;
358	  const hasActiveApplication = (appsRes.data ?? []).length > 0;
359	
360	  return jsonResponse(200, {
361	    listing,
362	    conditions,
363	    sample_videos: videosRes.data ?? [],
364	    eligibility: {
365	      eligible,
366	      failed_conditions: failed,
367	      has_active_application: hasActiveApplication,
368	    },
369	  });
370	});
