1	// Smoke test for the deployed get-listing-detail edge function (US-039).
2	//
3	// Usage: bun run scripts/test/get-listing-detail.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks JWT-authed tests; SUPABASE_SERVICE_ROLE_KEY unlocks the
6	// ineligibility case (needs to mutate creator_profiles.tiktok_follower_count
7	// below threshold + restore it). Missing either secret SKIPs the
8	// corresponding assertions with a printed notice rather than failing.
9	//
10	// Asserts:
11	//   1. Missing Authorization → 401 UNAUTHORIZED                               [always]
12	//   2. Non-Bearer token → 401 UNAUTHORIZED                                    [always]
13	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                        [always]
14	//   4. Lister-role JWT → 403 FORBIDDEN                                        [jwtSecret]
15	//   5. Malformed JSON body → 400 INVALID_JSON                                 [jwtSecret]
16	//   6. Missing listing_id → 400 INVALID_REQUEST                               [jwtSecret]
17	//   7. Non-UUID listing_id → 400 INVALID_REQUEST                              [jwtSecret]
18	//   8. Unknown listing_id → 404 LISTING_NOT_FOUND                             [jwtSecret]
19	//   9. Seed creator + seed listing (1k/500 thresholds, creator has 93.7M/15k)
20	//      → 200 with eligible:true, conditions[] containing both pre+post,
21	//        sample_videos, has_active_application:false                          [jwtSecret]
22	//  10. Same call after mutating creator_profiles.tiktok_follower_count to 500
23	//      → 200 with eligible:false AND failed_conditions including tiktok
24	//        min_followers with required=1000, actual=500                         [jwtSecret + serviceRole]
25	
26	const supabaseUrl = process.env.SUPABASE_URL;
27	const anonKey = process.env.SUPABASE_ANON_KEY;
28	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
29	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
30	if (!supabaseUrl || !anonKey) {
31	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
32	  process.exit(1);
33	}
34	if (!jwtSecret) {
35	  console.log(
36	    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–10",
37	  );
38	}
39	if (!serviceRoleKey) {
40	  console.log(
41	    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertion 10 (ineligible)",
42	  );
43	}
44	
45	const endpoint = `${supabaseUrl}/functions/v1/get-listing-detail`;
46	
47	// Seed fixtures — same UUIDs used by other smoke tests.
48	const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
49	const SEED_LISTING_ID = "11111111-1111-1111-1111-111111111010";
50	
51	const encoder = new TextEncoder();
52	
53	function b64url(bytes: Uint8Array): string {
54	  let s = "";
55	  for (const b of bytes) s += String.fromCharCode(b);
56	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
57	}
58	
59	async function signMarketifyJwt(
60	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
61	  secret: string,
62	): Promise<string> {
63	  const now = Math.floor(Date.now() / 1000);
64	  const payload = { ...claims, iat: now, exp: now + 300 };
65	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
66	  const body = b64url(encoder.encode(JSON.stringify(payload)));
67	  const signingInput = `${header}.${body}`;
68	  const key = await crypto.subtle.importKey(
69	    "raw",
70	    encoder.encode(secret),
71	    { name: "HMAC", hash: "SHA-256" },
72	    false,
73	    ["sign"],
74	  );
75	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
76	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
77	}
78	
79	async function post(
80	  bodyValue: string | Record<string, unknown> | null,
81	  authHeader: string | null,
82	) {
83	  const headers: Record<string, string> = {
84	    "Content-Type": "application/json",
85	    apikey: anonKey!,
86	  };
87	  if (authHeader) headers["Authorization"] = authHeader;
88	  const res = await fetch(endpoint, {
89	    method: "POST",
90	    headers,
91	    body: bodyValue == null
92	      ? undefined
93	      : typeof bodyValue === "string"
94	      ? bodyValue
95	      : JSON.stringify(bodyValue),
96	  });
97	  const data = await res.json().catch(() => null);
98	  return { status: res.status, data };
99	}
100	
101	function expect(label: string, cond: boolean, ctx: unknown) {
102	  if (!cond) {
103	    console.error(`FAIL ${label}:`, JSON.stringify(ctx, null, 2));
104	    process.exit(1);
105	  }
106	  console.log(`ok — ${label}`);
107	}
108	
109	async function setCreatorMetric(
110	  column: "tiktok_follower_count",
